import heapq
from collections import defaultdict

def dijkstra(graph, start_node):
    distances = {node: float('inf') for node in graph}
    distances[start_node] = 0
    priority_queue = [(0, start_node)]

    while priority_queue:
        current_distance, current_node = heapq.heappop(priority_queue)

        if current_distance > distances[current_node]:
            continue

        for neighbor, weight in graph[current_node].items():
            distance = current_distance + weight
            if distance < distances[neighbor]:
                distances[neighbor] = distance
                heapq.heappush(priority_queue, (distance, neighbor))
    return distances

def get_odd_degree_vertices(graph):
    degrees = {}
    for node in graph:
        degrees[node] = len(graph[node])

    return [node for node, degree in degrees.items() if degree % 2 != 0]

def get_all_pairs_shortest_paths_for_odd(graph, odd_vertices):
    odd_distances = defaultdict(dict)
    for u in odd_vertices:
        dists_from_u = dijkstra(graph, u)
        for v in odd_vertices:
            if u != v:
                odd_distances[u][v] = dists_from_u[v]
    return odd_distances

def min_weight_perfect_matching(odd_vertices, odd_distances):
    num_odd = len(odd_vertices)
    if num_odd == 0:
        return 0, []

    dp = [float('inf')] * (1 << num_odd)
    dp[0] = 0

    path_reconstruction = {}

    for mask in range(1, 1 << num_odd):
        u_idx = -1
        for i in range(num_odd):
            if (mask >> i) & 1:
                u_idx = i
                break

        u_node = odd_vertices[u_idx]

        for v_idx in range(u_idx + 1, num_odd):
            if (mask >> v_idx) & 1:
                v_node = odd_vertices[v_idx]

                cost_of_pair = odd_distances[u_node][v_node]

                remaining_mask = mask ^ (1 << u_idx) ^ (1 << v_idx)

                if dp[remaining_mask] + cost_of_pair < dp[mask]:
                    dp[mask] = dp[remaining_mask] + cost_of_pair
                    path_reconstruction[mask] = (u_node, v_node, cost_of_pair, remaining_mask)

    added_edges = []
    current_mask = (1 << num_odd) - 1

    while current_mask > 0:
        if current_mask not in path_reconstruction:
            break 

        u, v, cost, prev_mask = path_reconstruction[current_mask]
        added_edges.append((u, v, cost))
        current_mask = prev_mask

    return dp[(1 << num_odd) - 1], added_edges

def chinese_postman_problem(graph):
    initial_edge_sum = 0
    processed_edges = set() 
    for u in graph:
        for v, weight in graph[u].items():
            if (u, v) not in processed_edges and (v, u) not in processed_edges:
                initial_edge_sum += weight
                processed_edges.add((u, v))
                processed_edges.add((v, u))

    odd_vertices = get_odd_degree_vertices(graph)

    if not odd_vertices:
        return initial_edge_sum, []

    odd_distances = get_all_pairs_shortest_paths_for_odd(graph, odd_vertices)

    added_weight, paths_to_add = min_weight_perfect_matching(odd_vertices, odd_distances)

    total_min_cost = initial_edge_sum + added_weight

    return total_min_cost, paths_to_add
